using System;
using System.Diagnostics;

public class PdfGenerator
{
    public static void GeneratePdf(string htmlPath, string pdfPath, PageSize pageSize = PageSize.A4, Orientation orientation = Orientation.Portrait)
    {
        var options = new[]
        {
            $"--page-size {pageSize}",
            $"--orientation {orientation}",
            $"--load-media-error-policy ignore",
            $"--enable-local-file-access"
        };

        using (var process = new Process())
        {
            process.StartInfo.FileName = "wkhtmltopdf";
            process.StartInfo.Arguments = string.Join(" ", options) + $" \"{htmlPath}\" \"{pdfPath}\"";
            process.StartInfo.UseShellExecute = false;
            process.StartInfo.RedirectStandardError = true;

            try
            {
                process.Start();
                process.WaitForExit();

                if (process.ExitCode != 0)
                {
                    throw new Exception($"wkhtmltopdf failed with exit code {process.ExitCode}");
                }
            }
            catch (Exception ex) when (ex is InvalidOperationException || ex is FileNotFoundException)
            {
                Console.WriteLine("Error: wkhtmltopdf not found. Please install it and try again.");
                Environment.Exit(1);
            }
        }
    }

    public enum PageSize
    {
        A4,
        Letter
    }

    public enum Orientation
    {
        Portrait,
        Landscape
    }
}